import java.util.*;class Solution{public static void main(String[]a){var s=new Scanner(System.in);int L=s.nextInt(),C=s.nextInt();s.nextLine();char[][]G=new char[L][];int r=0,c=0;var T=new ArrayList<int[]>();for(int i=0;i<L;i++){G[i]=s.nextLine().toCharArray();for(int j=0;j<C;j++){if(G[i][j]=='@'){r=i;c=j;}if(G[i][j]=='T')T.add(new int[]{i,j});}}int[]dr={1,0,-1,0},dc={0,1,0,-1};String[]nm={"SOUTH","EAST","NORTH","WEST"};char[]ds="SENW".toCharArray();int d=0,b=0,v=0;var P=new ArrayList<String>();var V=new HashSet<String>();for(;;){var k=r+","+c+","+d+","+b+","+v+","+Arrays.deepToString(G);if(!V.add(k)){System.out.println("LOOP");return;}char h=G[r][c];for(int i=0;i<4;i++)if(h==ds[i])d=i;if(h=='B')b^=1;if(h=='I')v^=1;if(h=='T')for(var t:T)if(t[0]!=r||t[1]!=c){r=t[0];c=t[1];break;}int[]p=v?new int[]{3,2,1,0}:new int[]{0,1,2,3};int nr=r+dr[d],nc=c+dc[d];char e=G[nr][nc];if(e=='#'||(e=='X'&&b==0))for(int q:p){nr=r+dr[q];nc=c+dc[q];e=G[nr][nc];if(e!='#'&&(e!='X'||b>0)){d=q;break;}}r=nr;c=nc;P.add(nm[d]);if(G[r][c]=='X'&&b>0)G[r][c]=' ';if(G[r][c]=='$'){for(var x:P)System.out.println(x);return;}}}}